        val = cli_args.get(decl['arg'])
        if val is not None:
            return val, 'arg'
    else:
        # Also check with param name (for backward compatibility)
        val = cli_args.get(name)
        if val is not None:
            return val, 'arg'

    # File, env, default sources
    if 'file' in decl:
        val = get_file_value(decl['file'])
        if val is not None:
            return val, 'file'

    if 'env' in decl:
        val = get_env_value(decl['env'])
        if val is not None:
            return val, 'env'

    if 'default' in decl:
        return decl['default'], 'default'

    return None, None


def check_primary_store_config(schema: dict[str, Any], primary_store_url: str | None) -> str | None:
    """Validate primary-store configuration.

